#!/bin/bash\n# KayOS ISO Builder\n# Pastikan xorriso dan squashfs-tools terinstall\n\nISO_NAME=KayOS-v0.2.0.iso\nBUILD_DIR=iso_root\n\nmkdir -p $BUILD_DIR\n# (Di sini Anda akan menyalin sistem base Linux/Debian)\n\n# Inject KayOS\ncp target/release/kayky $BUILD_DIR/usr/bin/kayos\n\n# Build ISO\nxorriso -as mkisofs -o $ISO_NAME -b isolinux/isolinux.bin -c isolinux/boot.cat -no-emul-boot -boot-load-size 4 -boot-info-table $BUILD_DIR\n\necho 'ISO created: $ISO_NAME'
